"use client"

import { useState } from "react"
import { MapPin, Mail, Linkedin, Phone } from "lucide-react"
import { useTranslations } from "@/lib/i18n/context"

interface ContactSectionProps {
  currentPage?: number
}

export function ContactSection({ currentPage = 6 }: ContactSectionProps) {
  const t = useTranslations()
  const [formData, setFormData] = useState({
    name: "",
    email: "",
    subject: "",
    message: ""
  })

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault()
    // Handle form submission
    console.log("Form submitted:", formData)
    alert("Thank you for your message! I'll get back to you soon.")
    setFormData({ name: "", email: "", subject: "", message: "" })
  }

  return (
    <section id="contact" className="min-h-screen bg-background py-20 px-8">
      <div className="max-w-6xl mx-auto">
        <div className="grid lg:grid-cols-2 gap-12">
          {/* Contact Info */}
          <div>
            <h2 className="text-primary text-3xl font-bold mb-6">{t.contact.title}</h2>
            <p className="text-foreground/80 text-lg leading-relaxed mb-8">
              {t.contact.description}
            </p>

            <div className="space-y-4">
              <div className="flex items-center gap-4">
                <MapPin className="w-5 h-5 text-primary" />
                <div>
                  <span className="text-foreground/50 text-xs uppercase tracking-widest">{t.contact.address}:</span>
                  <p className="text-foreground">Taastrup, 2630 Denmark</p>
                </div>
              </div>
              <div className="flex items-center gap-4">
                <Mail className="w-5 h-5 text-primary" />
                <div>
                  <span className="text-foreground/50 text-xs uppercase tracking-widest">Email:</span>
                  <p className="text-foreground">miriamdarwish@hotmail.com</p>
                </div>
              </div>
              <div className="flex items-center gap-4">
                <Phone className="w-5 h-5 text-primary" />
                <div>
                  <span className="text-foreground/50 text-xs uppercase tracking-widest">Phone:</span>
                  <p className="text-foreground">+45 537 537 37</p>
                </div>
              </div>
              <div className="flex items-center gap-4">
                <Linkedin className="w-5 h-5 text-primary" />
                <div>
                  <span className="text-foreground/50 text-xs uppercase tracking-widest">LinkedIn:</span>
                  <a 
                    href="https://linkedin.com/in/miriamdarwish" 
                    target="_blank" 
                    rel="noopener noreferrer"
                    className="text-foreground hover:text-primary transition-colors block"
                  >
                    linkedin.com/in/miriamdarwish
                  </a>
                </div>
              </div>
            </div>
          </div>

          {/* Contact Form */}
          <div className="bg-primary p-8 rounded-lg">
            <form onSubmit={handleSubmit} className="space-y-6">
              <div>
                <input
                  type="text"
                  placeholder={t.contact.form.name}
                  value={formData.name}
                  onChange={(e) => setFormData({ ...formData, name: e.target.value })}
                  required
                  className="w-full bg-transparent border-b border-primary-foreground/30 pb-3 text-primary-foreground placeholder:text-primary-foreground/60 focus:border-primary-foreground outline-none transition-colors"
                />
              </div>
              <div>
                <input
                  type="email"
                  placeholder={t.contact.form.email}
                  value={formData.email}
                  onChange={(e) => setFormData({ ...formData, email: e.target.value })}
                  required
                  className="w-full bg-transparent border-b border-primary-foreground/30 pb-3 text-primary-foreground placeholder:text-primary-foreground/60 focus:border-primary-foreground outline-none transition-colors"
                />
              </div>
              <div>
                <input
                  type="text"
                  placeholder={t.contact.form.subject}
                  value={formData.subject}
                  onChange={(e) => setFormData({ ...formData, subject: e.target.value })}
                  required
                  className="w-full bg-transparent border-b border-primary-foreground/30 pb-3 text-primary-foreground placeholder:text-primary-foreground/60 focus:border-primary-foreground outline-none transition-colors"
                />
              </div>
              <div>
                <textarea
                  placeholder={t.contact.form.message}
                  value={formData.message}
                  onChange={(e) => setFormData({ ...formData, message: e.target.value })}
                  required
                  rows={4}
                  className="w-full bg-transparent border-b border-primary-foreground/30 pb-3 text-primary-foreground placeholder:text-primary-foreground/60 focus:border-primary-foreground outline-none transition-colors resize-none"
                />
              </div>
              <button
                type="submit"
                className="w-full py-4 border-2 border-primary-foreground text-primary-foreground font-medium uppercase tracking-widest hover:bg-primary-foreground hover:text-primary transition-colors rounded-full"
              >
                {t.contact.form.send}
              </button>
            </form>
          </div>
        </div>

        {/* Page Number */}
        <div className="mt-20">
          <div className="text-9xl font-bold text-primary/20">
            {String(currentPage).padStart(2, "0")}
          </div>
        </div>
      </div>
    </section>
  )
}
