function CircularProgress({ percentage, name, isVisible }: { percentage: number; name: string; isVisible: boolean }) {
  const [animatedPercentage, setAnimatedPercentage] = useState(0)
  const radius = 60
  const circumference = 2 * Math.PI * radius
  const strokeDashoffset = circumference - (animatedPercentage / 100) * circumference

  useEffect(() => {
    if (isVisible) {
      const duration = 1500
      const startTime = performance.now()
      
      const animate = (currentTime: number) => {
        const elapsed = currentTime - startTime
        const progress = Math.min(elapsed / duration, 1)
        const easeOut = 1 - Math.pow(1 - progress, 3)
        const current = Math.round(easeOut * percentage)
        setAnimatedPercentage(current)
        
        if (progress < 1) {
          requestAnimationFrame(animate)
        }
      }
      
      requestAnimationFrame(animate)
    } else {
      setAnimatedPercentage(0)
    }
  }, [isVisible, percentage])

  return (
    <div className="flex flex-col items-center">
      <div className="relative w-36 h-36">
        <svg className="w-full h-full transform -rotate-90">
          <circle
            cx="72"
            cy="72"
            r={radius}
            fill="none"
            stroke="currentColor"
            strokeWidth="8"
            className="text-muted"
          />
          <circle
            cx="72"
            cy="72"
            r={radius}
            fill="none"
            stroke="currentColor"
            strokeWidth="8"
            strokeDasharray={circumference}
            strokeDashoffset={strokeDashoffset}
            strokeLinecap="round"
            className="text-primary transition-none"
          />
        </svg>
        <div className="absolute inset-0 flex items-center justify-center">
          <span className="text-2xl font-bold text-primary">{animatedPercentage}%</span>
        </div>
      </div>
      <span className="text-muted-foreground mt-4 text-center">{name}</span>
    </div>
  )
}

function ProgressBar({ percentage, name, isVisible }: { percentage: number; name: string; isVisible: boolean }) {
  const [animatedPercentage, setAnimatedPercentage] = useState(0)

  useEffect(() => {
    if (isVisible) {
      const duration = 1500
      const startTime = performance.now()
      
      const animate = (currentTime: number) => {
        const elapsed = currentTime - startTime
        const progress = Math.min(elapsed / duration, 1)
        const easeOut = 1 - Math.pow(1 - progress, 3)
        const current = Math.round(easeOut * percentage)
        setAnimatedPercentage(current)
        
        if (progress < 1) {
          requestAnimationFrame(animate)
        }
      }
      
      requestAnimationFrame(animate)
    } else {
      setAnimatedPercentage(0)
    }
  }, [isVisible, percentage])

  return (
    <div className="space-y-2">
      <div className="flex justify-between items-center">
        <span className="text-muted-foreground">{name}</span>
        <span className="text-muted-foreground">{animatedPercentage}%</span>
      </div>
      <div className="h-2 bg-muted rounded-full overflow-hidden">
        <div
          className="h-full bg-primary rounded-full transition-none"
          style={{ width: `${animatedPercentage}%` }}
        />
      </div>
    </div>
  )
}

interface SkillsSectionProps {
  currentPage?: number
}

export function SkillsSection({ currentPage = 5 }: SkillsSectionProps) {
  const [isVisible, setIsVisible] = useState(false)
  const sectionRef = useRef<HTMLElement>(null)
  const t = useTranslations()

  useEffect(() => {
    const observer = new IntersectionObserver(
      ([entry]) => {
        if (entry.isIntersecting) {
          setIsVisible(true)
        }
      },
      { threshold: 0.2 }
    )

    if (sectionRef.current) {
      observer.observe(sectionRef.current)
    }

    return () => observer.disconnect()
  }, [])

  return (
    <section ref={sectionRef} id="skills" className="min-h-screen bg-card py-20 px-8">
      <div className="max-w-6xl mx-auto">
        <h2 className="text-primary text-3xl font-bold mb-12">{t.skills.title}</h2>

        {/* Circular Skills */}
        <div className="grid grid-cols-2 md:grid-cols-4 gap-8 mb-16">
          {circularSkills.map((skill, index) => (
            <CircularProgress key={index} percentage={skill.percentage} name={skill.name} isVisible={isVisible} />
          ))}
        </div>

        {/* Bar Skills */}
        <div className="grid md:grid-cols-2 gap-x-12 gap-y-6 mb-16">
          {barSkills.map((skill, index) => (
            <ProgressBar key={index} percentage={skill.percentage} name={skill.name} isVisible={isVisible} />
          ))}
        </div>

        {/* Technologies - Card Groups with Icons */}
        <div className="mb-16">
          <h3 className="text-primary text-xl font-semibold mb-6">{t.skills.technologies}</h3>
          <div className="grid md:grid-cols-2 gap-6">
            {technologyGroups.map((group) => {
              const GroupIcon = group.icon
              return (
                <div key={group.category} className="bg-secondary/30 p-6 rounded-xl border border-border/50">
                  <div className="flex items-center gap-3 mb-4">
                    <div className="w-10 h-10 rounded-lg bg-primary/20 flex items-center justify-center">
                      <GroupIcon className="w-5 h-5 text-primary" />
                    </div>
                    <h4 className="text-foreground font-semibold">{group.category}</h4>
                  </div>
                  <div className="flex flex-wrap gap-2">
                    {group.tools.map((tool) => {
                      const ToolIcon = tool.icon
                      return (
                        <div
                          key={tool.name}
                          className="flex items-center gap-2 bg-background/50 px-3 py-2 rounded-lg text-sm text-muted-foreground hover:text-foreground hover:bg-background transition-colors"
                        >
                          <ToolIcon className="w-4 h-4" />
                          <span>{tool.name}</span>
                        </div>
                      )
                    })}
                  </div>
                </div>
              )
            })}
          </div>
        </div>

        {/* Personal Skills */}
        <div className="mb-12">
          <h3 className="text-primary text-xl font-semibold mb-6">{t.skills.personalSkills}</h3>
          <div className="grid md:grid-cols-3 gap-4">
            {t.skills.personalSkillsList.map((skill, index) => (
              <div key={index} className="bg-secondary/50 px-4 py-3 rounded-lg text-foreground/80">
                {skill}
              </div>
            ))}
          </div>
        </div>

        {/* Languages */}
        <div className="mb-12">
          <h3 className="text-primary text-xl font-semibold mb-6">{t.skills.languages}</h3>
          <div className="flex flex-wrap gap-4">
            <span className="bg-primary/20 text-primary px-6 py-2 rounded-full font-medium">Dutch</span>
            <span className="bg-primary/20 text-primary px-6 py-2 rounded-full font-medium">English</span>
            <span className="bg-primary/20 text-primary px-6 py-2 rounded-full font-medium">Danish</span>
          </div>
        </div>

        {/* Certifications */}
        <div className="mb-12">
          <h3 className="text-primary text-xl font-semibold mb-6">{t.skills.certifications}</h3>
          <div className="bg-secondary/50 p-6 rounded-lg inline-block">
            <p className="text-foreground font-medium">IPMA (PMO)</p>
            <p className="text-muted-foreground text-sm">International Project Management Association</p>
          </div>
        </div>

        {/* Education */}
        <div className="mb-12">
          <h3 className="text-primary text-xl font-semibold mb-6">{t.skills.education}</h3>
          <div className="bg-secondary/50 p-6 rounded-lg">
            <p className="text-foreground font-medium">Bachelor of Tourism Management</p>
            <p className="text-primary text-sm">InHolland in Amsterdam, Netherlands</p>
            <p className="text-muted-foreground text-sm">2018</p>
          </div>
        </div>

        {/* Page Number */}
        <div className="mt-20">
          <div className="text-9xl font-bold text-primary/20">
            {String(currentPage).padStart(2, "0")}
          </div>
        </div>
      </div>
    </section>
  )
}
